// Get data from previous nodes
const parsedData = $node['Parse JSON Output'].json;
const descriptionData = $json;
const editFieldsData = $node['Edit Fields'].json;

// Extract values with proper fallbacks
const title = parsedData.title || 'Untitled';
const story = parsedData.story || 'No story';
const quote = parsedData.quote || 'No quote';
const description = descriptionData.output || 'Ancient Roman wisdom and stoic philosophy';
const script = `${story} ${quote}`;
const numberOfImages = editFieldsData.numberOfImages || 2;
const timeToPublish = editFieldsData.timeToPublish || new Date().toISOString();
const keywords = editFieldsData.videoKeywords || 'stoic,ancient rome';

// Create clean filename
const cleanTitle = title
  .toLowerCase()
  .replace(/['''"]/g, '')
  .replace(/[^a-z0-9]/g, '_')
  .replace(/_{2,}/g, '_')
  .replace(/^_+|_+$/g, '')
  .substring(0, 50);

const filename = cleanTitle || 'untitled';

// Return structured data
return {
  title: title,
  description: description,
  script: script,
  numberOfImages: numberOfImages,
  timeToPublish: timeToPublish,
  keywords: keywords,
  filename: filename,
  story: story,
  quote: quote
};

