const output = $json.output;
try {
  // Clean the output to remove any markdown formatting
  const cleanOutput = output.replace(/json\n?/g, '').replace(/\n?/g, '').trim();

  const parsed = JSON.parse(cleanOutput);

  // Ensure all required fields exist
  const result = {
    title: parsed.title || 'Untitled',
    story: parsed.story || 'No story generated',
    quote: parsed.quote || 'No quote generated'
  };

  return [{
    json: result
  }];
} catch (error) {
  // Improved error handling with fallback values
  console.error('JSON Parse Error:', error.message);
  console.error('Raw output:', output);

  // Try to extract values using regex as fallback
  const titleMatch = output.match(/"title"\s*:\s*"([^"]+)"/i);
  const storyMatch = output.match(/"story"\s*:\s*"([^"]+)"/i);
  const quoteMatch = output.match(/"quote"\s*:\s*"([^"]+)"/i);

  return [{
    json: {
      title: titleMatch ? titleMatch[1] : 'Wisdom of the Ages',
      story: storyMatch ? storyMatch[1] : 'In the heart of ancient Rome, a philosopher contemplated the nature of virtue and wisdom.',
      quote: quoteMatch ? quoteMatch[1] : 'The happiness of your life depends upon the quality of your thoughts. - Marcus Aurelius',
      error: 'JSON Parse Error - Used fallback values',
      rawOutput: output
    }
  }];
}

// Get the input from the Image Generation agent
const input = $json.output;

// Get numberOfImages from the Code node
let numberOfImages;
try {
  numberOfImages = $('Code').item.json.numberOfImages || 3;
} catch (error) {
  console.log('Could not get numberOfImages from Code node, defaulting to 3');
  numberOfImages = 3;
}

// Get filename from Code node for consistent naming
let baseFilename;
try {
  baseFilename = $('Code').item.json.filename || 'untitled';
} catch (error) {
  console.log('Could not get filename from Code node, using default');
  baseFilename = 'untitled';
}

console.log('=== PROCESSING IMAGE PROMPTS ===');
console.log('Requested images:', numberOfImages);
console.log('Base filename:', baseFilename);
console.log('Input:', input);

// Handle empty or invalid input
if (!input || typeof input !== 'string') {
  console.error('Invalid input from Image Generation agent');
  const fallbackPrompts = [];
  for (let i = 1; i <= numberOfImages; i++) {
    fallbackPrompts.push({
      json: {
        prompt: `Ancient Roman scene ${i}: Marcus Aurelius contemplating wisdom in marble hall with golden sunlight and classical architecture`,
        imageIndex: i,
        filename: `${baseFilename}_image_${i}`
      }
    });
  }
  return fallbackPrompts;
}

// Clean and split the input text
const lines = input
  .split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0);

const imagePrompts = [];

// Extract prompts from lines
for (const line of lines) {
  let prompt = line.replace(/^Image\s+Prompt\s*:?\s*/i, '').trim();
  prompt = prompt.replace(/^["']|["']$/g, '').trim();
  prompt = prompt.replace(/^\\|\\$/g, '').trim();

  if (prompt.length > 10 && 
      !prompt.toLowerCase().includes('requirement') &&
      !prompt.toLowerCase().includes('strict output') &&
      !prompt.toLowerCase().includes('format:')) {
    imagePrompts.push(prompt);
  }
}

console.log('Extracted prompts:', imagePrompts);

// Ensure we have exactly the requested number of prompts
while (imagePrompts.length < numberOfImages) {
  const index = imagePrompts.length + 1;
  const fallback = `Ancient Roman philosophical scene ${index}: Stoic philosopher in contemplation surrounded by classical marble columns and warm golden light`;
  imagePrompts.push(fallback);
  console.log(`Added fallback prompt ${index}:`, fallback);
}

// Trim to exact number requested
const finalPrompts = imagePrompts.slice(0, numberOfImages);

console.log('Final prompts count:', finalPrompts.length);
console.log('Final prompts:', finalPrompts);

// Return array of objects for n8n processing
return finalPrompts.map((prompt, index) => ({
  json: {
    prompt: prompt,
    imageIndex: index + 1,
    filename: `${baseFilename}_image_${index + 1}`
  }
}));

// deAPI Image Generation
const imagePrompts = $input.all();
const results = [];

const DEAPI_KEY = "YOUR_DEAPI_KEY_HERE";
const BASE_URL = "https://api.deapi.ai";

console.log('🚀 Starting deAPI image generation for', imagePrompts.length, 'prompts');

for (let i = 0; i < imagePrompts.length; i++) {
  const item = imagePrompts[i].json;
  const prompt = item.prompt;
  const filename = item.filename;
  const imageIndex = item.imageIndex;

  console.log(`📸 Processing image ${imageIndex}/${imagePrompts.length}: ${filename}`);
  console.log(`🎨 Prompt: ${prompt.substring(0, 100)}...`);

  try {
    console.log('📤 Submitting job to deAPI...');

    const requestBody = {
      prompt: prompt,
      model: "Flux1schnell",
      width: 1024,
      height: 1024,
      seed: Math.floor(Math.random() * 1000000),
      steps: 4
    };

    const jobResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: `${BASE_URL}/api/v1/client/txt2img`,
      headers: {
        'Authorization': `Bearer ${DEAPI_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(requestBody),
      timeout: 10000
    });

    const requestId = jobResponse.data?.request_id || jobResponse.request_id;

    if (!requestId) {
      throw new Error('No request_id in response from deAPI');
    }

    console.log(`✅ Job submitted. Request ID: ${requestId}`);

    let imageUrl = null;
    let attempts = 0;
    const maxAttempts = 60;

    console.log('⏳ Waiting for image generation...');

    while (attempts < maxAttempts) {
      await new Promise(resolve => setTimeout(resolve, 3000));
      attempts++;

      try {
        const statusResponse = await this.helpers.httpRequest({
          method: 'GET',
          url: `${BASE_URL}/api/v1/client/request-status/${requestId}`,
          headers: {
            'Authorization': `Bearer ${DEAPI_KEY}`
          },
          timeout: 10000
        });

        const status = statusResponse.data?.status || statusResponse.status;
        console.log(`Status check ${attempts}/${maxAttempts}: ${status || 'unknown'}`);

        if (status === 'done' || status === 'completed') {
          imageUrl = statusResponse.data?.result_url || statusResponse.result_url;
          console.log(`✅ Image ready!`);
          break;
        } else if (status === 'error' || status === 'failed') {
          const errorMsg = statusResponse.data?.error || statusResponse.error || 'Unknown error';
          throw new Error(`Job failed: ${errorMsg}`);
        }

      } catch (statusError) {
        console.error(`Error checking status (attempt ${attempts}):`, statusError.message);
        if (attempts >= maxAttempts) {
          throw statusError;
        }
      }
    }

    if (!imageUrl) {
      throw new Error('Image generation timeout after 3 minutes');
    }

    console.log(`📥 Downloading image...`);

    const imageResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: imageUrl,
      encoding: 'arraybuffer',
      timeout: 30000
    });

    const base64Image = Buffer.from(imageResponse).toString('base64');

    if (!base64Image || base64Image.length < 1000) {
      throw new Error('Invalid or empty image data received');
    }

    results.push({
      json: {
        filename: `${filename}.png`,
        imageIndex: imageIndex,
        imageData: base64Image,
        prompt: prompt,
        success: true,
        downloadUrl: imageUrl,
        imageSize: base64Image.length,
        requestId: requestId,
        api: 'deAPI',
        model: 'Flux1schnell'
      }
    });

    console.log(`✅ Successfully generated image ${imageIndex}: ${filename} (${Math.round(base64Image.length / 1024)}KB)`);

  } catch (error) {
    console.error(`❌ Failed to generate image ${imageIndex}:`, error.message);

    results.push({
      json: {
        filename: `${filename}.png`,
        imageIndex: imageIndex,
        imageData: null,
        prompt: prompt,
        success: false,
        error: error.message,
        downloadUrl: null
      }
    });
  }

  if (i < imagePrompts.length - 1) {
    console.log('⏳ Waiting 3 seconds before next job...');
    await new Promise(resolve => setTimeout(resolve, 3000));
  }
}

const successCount = results.filter(r => r.json.success).length;
console.log(`🎯 Completed: ${successCount}/${results.length} images generated successfully with deAPI`);

return results;

// Log generated images for debugging
const images = $input.all();

console.log('=== GENERATED IMAGES DEBUG ===');
console.log('Total images:', images.length);

images.forEach((item, index) => {
  const data = item.json;
  console.log(`\nImage ${index + 1}:`);
  console.log('Filename:', data.filename);
  console.log('Success:', data.success);
  console.log('Image size:', data.imageSize ? `${Math.round(data.imageSize / 1024)}KB` : 'N/A');
  console.log('Prompt:', data.prompt ? data.prompt.substring(0, 100) + '...' : 'N/A');

  if (!data.success) {
    console.log('Error:', data.error);
  }
});

// Pass through all images for next node
return images;

// Convert base64 image data to proper n8n binary format
const allImages = $input.all();
const results = [];

console.log('=== CONVERTING FOR N8N VIEW/DOWNLOAD ===');
console.log('Total images to convert:', allImages.length);

for (let i = 0; i < allImages.length; i++) {
  const item = allImages[i];
  const data = item.json;

  console.log(`\nProcessing image ${i + 1}:`);
  console.log('Filename:', data.filename);
  console.log('Success:', data.success);
  console.log('Has image data:', !!data.imageData);

  if (!data.imageData || !data.success) {
    console.log('❌ Skipping - no image data');
    continue;
  }

  try {
    const imageBuffer = Buffer.from(data.imageData, 'base64');
    console.log(`✅ Converted ${data.filename} - Size: ${Math.round(imageBuffer.length / 1024)}KB`);

    const result = {
      json: {
        filename: data.filename,
        imageIndex: data.imageIndex,
        prompt: data.prompt,
        success: true,
        size: imageBuffer.length,
        mimeType: 'image/png'
      },
      binary: {
        data: {
          data: imageBuffer.toString('base64'),
          mimeType: 'image/png',
          fileName: data.filename,
          fileExtension: 'png',
          fileSize: imageBuffer.length
        }
      }
    };

    results.push(result);

  } catch (error) {
    console.error(`❌ Failed to convert ${data.filename}:`, error.message);

    results.push({
      json: {
        filename: data.filename,
        imageIndex: data.imageIndex,
        prompt: data.prompt,
        success: false,
        error: error.message
      }
    });
  }
}

console.log(`\n📊 Successfully converted ${results.length} images for n8n viewing`);

return results;

console.log('=== DEBUG INFO ===');
console.log('Script from Code node:', $node['Code'].json['script']);
console.log('Script length:', $node['Code'].json['script']?.length);
console.log('Filename:', $node['Code'].json['filename']);

// Return the data so HTTP Request can still use it
return $input.all();

// Get the script from the Code node
const script = $node['Code'].json['script'] || 'Test message';
const filename = $node['Code'].json['filename'] || 'test';

console.log('=== MAKING TTS REQUEST ===');
console.log('Script:', script.substring(0, 100) + '...');

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'YOUR_KOKORO_TTS_URL_HERE/v1/audio/speech',
