} catch (error) {
  console.error('❌ TTS request failed:', error.message);
  console.error('Full error:', error);

  return {
    json: {
      success: false,
      error: error.message,
      filename: `error_${filename}.txt`
    }
  };
}

// FINAL VERSION — AUDIO IS SOURCE OF TRUTH (SYNC FIXED)

try {
  const kokoroData = $('kokoro').item;
  const script = $('Code').item.json.script || '';

  console.log('=== CALCULATING AUDIO DURATION (AUDIO-DRIVEN) ===');

  if (!kokoroData?.binary?.data?.data) {
    throw new Error('No audio binary data found from kokoro node');
  }

  const audioBuffer = Buffer.from(kokoroData.binary.data.data, 'base64');
  const fileSizeBytes = audioBuffer.length;
  const fileSizeKB = Math.round(fileSizeBytes / 1024);

  const wordsPerMinute = 145;
  const wordCount = script.trim().split(/\s+/).length;
  const estimatedDuration = (wordCount / wordsPerMinute) * 60;

  const finalDuration = Math.round(estimatedDuration * 100) / 100;

  console.log(`📝 Word count: ${wordCount}`);
  console.log(`🎙 Estimated audio duration: ${finalDuration}s`);
  console.log(`🔊 Audio size: ${fileSizeKB} KB`);

  return {
    json: {
      success: true,
      durationSeconds: finalDuration,
      durationFormatted: `0:${Math.round(finalDuration)}`,
      wordCount,
      wordsPerMinute,
      estimatedDuration: finalDuration,
      fileSizeBytes,
      fileSizeKB,
      filename: kokoroData.json.filename,
      note: "Duration derived from narration to keep audio, captions, and video in sync"
    }
  };

} catch (error) {
  console.error('❌ Failed to calculate audio duration:', error.message);

  return {
    json: {
      success: false,
      error: error.message,
      durationSeconds: 0,
      durationFormatted: "0:00",
      wordCount: 0,
      filename: "unknown"
    }
  };
}

// Collect images from conversion node
const images = $('conversion').all()
  .filter(i => i.binary && i.binary.data)
  .map(i => i.binary.data.data);

// Collect audio from kokoro
const audioItem = $('kokoro').first();

if (!audioItem?.binary?.data?.data) {
