// ===== CODE4 – FINAL STABLE VERSION =====

const payload = $json;

console.log("📤 Sending payload to Python server");
console.log("Images:", payload.images?.length);
console.log("Duration:", payload.duration);

const response = await this.helpers.httpRequest({
