// Code5 — AUDIO-SYNCED, WORD-WEIGHTED SRT (PRODUCTION SAFE)

const script = $node['Code'].json.script || '';
const filename = $node['Code'].json.filename || 'video';
const audioDuration = $node['calculate audio duration'].json.durationSeconds;

console.log('=== GENERATING WORD-WEIGHTED SRT ===');
console.log('Duration:', audioDuration, 's');

// ---------- HELPERS ----------
function formatSRTTime(seconds) {
  const hrs = Math.floor(seconds / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);
  const ms = Math.floor((seconds % 1) * 1000);
  return `${hrs.toString().padStart(2,'0')}:${mins.toString().padStart(2,'0')}:${secs.toString().padStart(2,'0')},${ms.toString().padStart(3,'0')}`;
}

// ---------- SPLIT SCRIPT ----------
const words = script.trim().split(/\s+/);
const captions = [];
let i = 0;

while (i < words.length) {
  const chunkSize = Math.min(5, words.length - i);
  captions.push(words.slice(i, i + chunkSize).join(' '));
  i += chunkSize;
}

// ---------- WORD-BASED TIMING ----------
const totalWords = words.length;
let currentTime = 0;
let srt = '';

captions.forEach((text, index) => {
  const wordCount = text.split(/\s+/).length;
  const segmentDuration = (wordCount / totalWords) * audioDuration;

  const start = currentTime;
  const end = currentTime + segmentDuration;
  currentTime = end;

  srt += `${index + 1}\n`;
  srt += `${formatSRTTime(start)} --> ${formatSRTTime(end)}\n`;
  srt += `${text}\n\n`;
});

console.log(`Generated ${captions.length} captions`);
console.log(`Total words: ${totalWords}`);

// ---------- OUTPUT ----------
const srtFilename = `captions_${filename}.srt`;
const base64SRT = Buffer.from(srt, 'utf8').toString('base64');

return {
  json: {
    success: true,
    filename: srtFilename,
    captionCount: captions.length,
    duration: audioDuration
  },
  binary: {
    data: {
      data: base64SRT,
      mimeType: 'application/x-subrip',
      fileName: srtFilename,
      fileExtension: 'srt'
    }
  }
};
